22:   return (cluster.features() & Upstream::ClusterInfo::Features::HTTP3) &&
23:          // USE_ALPN is only set when a TCP pool is also configured. Such cluster supports TCP
24:          // fallback.
25:          (cluster.features() & Upstream::ClusterInfo::Features::USE_ALPN);
