190: std::pair<uint32_t, bool> RetryStateImpl::parseRetryOn(absl::string_view config) {
191:   uint32_t ret = 0;
192:   bool all_fields_valid = true;
193:   for (const auto& retry_on : StringUtil::splitToken(config, ",", false, true)) {
194:     if (retry_on == Http::Headers::get().EnvoyRetryOnValues._5xx) {
195:       ret |= RetryPolicy::RETRY_ON_5XX;
196:     } else if (retry_on == Http::Headers::get().EnvoyRetryOnValues.GatewayError) {
197:       ret |= RetryPolicy::RETRY_ON_GATEWAY_ERROR;
198:     } else if (retry_on == Http::Headers::get().EnvoyRetryOnValues.ConnectFailure) {
199:       ret |= RetryPolicy::RETRY_ON_CONNECT_FAILURE;
200:     } else if (retry_on == Http::Headers::get().EnvoyRetryOnValues.EnvoyRateLimited) {
201:       ret |= RetryPolicy::RETRY_ON_ENVOY_RATE_LIMITED;
202:     } else if (retry_on == Http::Headers::get().EnvoyRetryOnValues.Retriable4xx) {
203:       ret |= RetryPolicy::RETRY_ON_RETRIABLE_4XX;
204:     } else if (retry_on == Http::Headers::get().EnvoyRetryOnValues.RefusedStream) {
205:       ret |= RetryPolicy::RETRY_ON_REFUSED_STREAM;
206:     } else if (retry_on == Http::Headers::get().EnvoyRetryOnValues.RetriableStatusCodes) {
207:       ret |= RetryPolicy::RETRY_ON_RETRIABLE_STATUS_CODES;
208:     } else if (retry_on == Http::Headers::get().EnvoyRetryOnValues.RetriableHeaders) {
209:       ret |= RetryPolicy::RETRY_ON_RETRIABLE_HEADERS;
210:     } else if (retry_on == Http::Headers::get().EnvoyRetryOnValues.Reset) {
211:       ret |= RetryPolicy::RETRY_ON_RESET;
212:     } else if (retry_on == Http::Headers::get().EnvoyRetryOnValues.ResetBeforeRequest) {
213:       ret |= RetryPolicy::RETRY_ON_RESET_BEFORE_REQUEST;
214:     } else if (retry_on == Http::Headers::get().EnvoyRetryOnValues.Http3PostConnectFailure) {
215:       ret |= RetryPolicy::RETRY_ON_HTTP3_POST_CONNECT_FAILURE;
216:     } else {
217:       all_fields_valid = false;
218:     }
219:   }
220: 
221:   return {ret, all_fields_valid};
222: }
