371: RetryStatus RetryStateImpl::shouldHedgeRetryPerTryTimeout(DoRetryCallback callback) {
372:   // A hedged retry on per try timeout is always retried if there are retries
373:   // left. NOTE: this is a bit different than non-hedged per try timeouts which
374:   // are only retried if the applicable retry policy specifies either
375:   // RETRY_ON_5XX or RETRY_ON_GATEWAY_ERROR. This is because these types of
376:   // retries are associated with a stream reset which is analogous to a gateway
377:   // error. When hedging on per try timeout is enabled, however, there is no
378:   // stream reset.
379:   return shouldRetry(RetryState::RetryDecision::RetryWithBackoff, callback);
380: }
